#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution {
public:
	vector<int> binaryTreeHeight(Node* root) {
		if (root == NULL) return {};
		vector<int> heights;
		return {1 + max(heights = Solution::binaryTreeHeight(root->left), heights = Solution::binaryTreeHeight(root->right))};
	}
};

int main() {
	Node root = {1, null, null};
	Solution solution;
	vector<int> heights = solution.binaryTreeHeight(&root);
	for (int height : heights) cout << height << ' ';
	return 0;
}
